  1→//! Symbolic expression types for representing constraints on function inputs.
  2→
  3→use std::collections::HashSet;
  4→
  5→use crate::types::ComplexKind;
  6→use serde::{Deserialize, Serialize};
  7→
  8→/// A symbolic expression representing a constraint on function inputs.
  9→#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
 10→#[serde(tag = "kind", rename_all = "snake_case")]
 11→pub enum SymExpr {
 12→    /// Reference to a function parameter, with optional field path.
 13→    /// e.g., param "config", path ["timeout"] represents config.timeout
 14→    Param {
 15→        name: String,
 16→        #[serde(default)]
 17→        path: Vec<String>,
 18→    },
 19→
 20→    /// A literal constant value.
 21→    Const(ConstValue),
 22→
 23→    /// Binary operation: left op right.
 24→    BinOp {
 25→        op: BinOpKind,
 26→        left: Box<SymExpr>,
 27→        right: Box<SymExpr>,
 28→    },
 29→
 30→    /// Unary operation: op operand.
 31→    UnOp {
 32→        op: UnOpKind,
 33→        operand: Box<SymExpr>,
 34→    },
 35→
 36→    /// Method/function call with symbolic arguments.
 37→    Call {
 38→        name: String,
 39→        receiver: Option<Box<SymExpr>>,
 40→        args: Vec<SymExpr>,
 41→    },
 42→
 43→    /// Could not be tracked symbolically — fall back to fuzzing.
 44→    Unknown,
 45→}
 46→
 47→/// A concrete constant value in a symbolic expression.
 48→#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
 49→#[serde(tag = "type", content = "value", rename_all = "snake_case")]
 50→pub enum ConstValue {
 51→    Int(i64),
 52→    Float(f64),
 53→    Str(String),
 54→    Bool(bool),
 55→    Null,
 56→    Undefined,
 57→    /// Complex constant (e.g., Date literal in a comparison).
 58→    /// `repr` is the underlying value the solver reasons about
 59→    /// (epoch millis for dates, digit string for bigint, codepoint for char).
 60→    Complex {
 61→        kind: ComplexKind,
 62→        repr: Box<ConstValue>,
 63→    },
 64→}
 65→
 66→/// Binary operators for symbolic expressions.
 67→#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash, Serialize, Deserialize)]
 68→#[serde(rename_all = "snake_case")]
 69→pub enum BinOpKind {
 70→    // Comparison
 71→    Eq,
 72→    Ne,
 73→    Lt,
 74→    Le,
 75→    Gt,
 76→    Ge,
 77→    // Arithmetic
 78→    Add,
 79→    Sub,
 80→    Mul,
 81→    Div,
 82→    Mod,
 83→    // Logical
 84→    And,
 85→    Or,
 86→    // Bitwise
 87→    BitwiseAnd,
 88→    BitwiseOr,
 89→    BitwiseXor,
 90→    // Shifts and bit-clear (Go-specific)
 91→    Shl,
 92→    Shr,
 93→    BitClear,
 94→    // JS-specific
 95→    In,
 96→    InstanceOf,
 97→}
 98→
 99→/// Collect all parameter names referenced in a symbolic expression tree.
100→/// Used for branch-parameter attribution — identifying which parameters
101→/// influence a given branch condition.
102→pub fn extract_param_names(expr: &SymExpr) -> HashSet<String> {
103→    let mut names = HashSet::new();
104→    collect_param_names(expr, &mut names);
105→    names
106→}
107→
108→fn collect_param_names(expr: &SymExpr, names: &mut HashSet<String>) {
109→    match expr {
110→        SymExpr::Param { name, .. } => {
111→            names.insert(name.clone());
112→        }
113→        SymExpr::Const(_) | SymExpr::Unknown => {}
114→        SymExpr::BinOp { left, right, .. } => {
115→            collect_param_names(left, names);
116→            collect_param_names(right, names);
117→        }
118→        SymExpr::UnOp { operand, .. } => {
119→            collect_param_names(operand, names);
120→        }
121→        SymExpr::Call {
122→            receiver, args, ..
123→        } => {
124→            if let Some(r) = receiver {
125→                collect_param_names(r, names);
126→            }
127→            for arg in args {
128→                collect_param_names(arg, names);
129→            }
130→        }
131→    }
132→}
133→
134→/// Unary operators for symbolic expressions.
135→#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash, Serialize, Deserialize)]
136→#[serde(rename_all = "snake_case")]
137→pub enum UnOpKind {
138→    Not,
139→    Neg,
140→    BitwiseNot,
141→    #[serde(alias = "typeof")]
142→    TypeOf,
143→}
