1280→        1 // Can only add
1281→    } else if arr.len() < 2 {
1282→        rng.random_range(0..3) // Remove, add, or mutate (no shuffle)
1283→    } else {
1284→        rng.random_range(0..4)
1285→    };
1286→    match op {
1287→        0 => {
1288→            // Remove element
1289→            let mut result = arr;
1290→            let idx = rng.random_range(0..result.len());
1291→            result.remove(idx);
1292→            json!(result)
1293→        }
1294→        1 => {
1295→            // Add element
1296→            let mut result = arr;
1297→            let new_elem = generate_random_value(element, rng, None);
1298→            result.push(new_elem);
1299→            json!(result)
1300→        }
1301→        2 => {
1302→            // Mutate element
1303→            let mut result = arr;
1304→            let idx = rng.random_range(0..result.len());
1305→            result[idx] = mutate_value(&result[idx], element, dictionary, rng);
1306→            json!(result)
1307→        }
1308→        _ => {
1309→            // Shuffle (swap two random elements)
1310→            let mut result = arr;
1311→            let i = rng.random_range(0..result.len());
1312→            let j = rng.random_range(0..result.len());
1313→            result.swap(i, j);
1314→            json!(result)
1315→        }
1316→    }
1317→}
