1533→fn crossover_string(a: &Value, b: &Value, rng: &mut impl Rng) -> (Value, Value) {
1534→    let (Some(sa), Some(sb)) = (a.as_str(), b.as_str()) else {
1535→        return if rng.random_bool(0.5) {
1536→            (a.clone(), b.clone())
1537→        } else {
1538→            (b.clone(), a.clone())
1539→        };
1540→    };
1541→
1542→    // Empty strings — fall back to uniform swap
